// Stage 8.6.6 — workflow JSON dry-run flags (no $env; staging n8n blocks env in expressions)
const inbound = $input.first().json;
return [{
  json: {
    ...inbound,
    dry_run: true,
    live_send_enabled: false
  }
}];

// Stage 8.6.3 — Staff Ask Luna WhatsApp Dry Run
// Extracts inbound staff WhatsApp message fields.
// Expected shape: { from, text, client_slug, channel }
// 'from' is the staff phone number (checked against allowlist by Staff API).
// 'text' is the natural-language question.
// No secrets extracted here. No DB writes.

const body = $input.first().json.body || $input.first().json;

const staffPhone  = String(body.from        || body.staff_phone || '').trim();
const question    = String(body.text        || body.question    || '').trim();
const clientSlug  = String(body.client_slug || 'wolfhouse-somo').trim();
const channel     = String(body.channel     || 'whatsapp').trim();

if (!staffPhone) {
  throw new Error('Missing required field: from (staff phone number)');
}
if (!question) {
  throw new Error('Missing required field: text (question)');
}

return [{
  json: {
    staff_phone:  staffPhone,
    question:     question,
    client_slug:  clientSlug,
    channel:      channel,
    _dry_run:     true
  }
}];

