// Stage 8.6.3 — format the Staff API answer into a dry-run reply log.
// No live WhatsApp send. whatsapp_sent is always false here.
// intent=unsupported_intent is handled: logs answer+suggestions, no send.

const apiResp    = $input.first().json;
const body       = apiResp.body || apiResp;  // fullResponse wraps in .body
const parsed     = $('Code - Parse Staff Message').first().json;

const intent     = String(body.intent     || 'unknown');
const answer     = String(body.answer     || '');
const rowCount   = typeof body.row_count === 'number' ? body.row_count : 0;
const hint       = body.intent_hint  ? String(body.intent_hint) : null;

// Build a WhatsApp-readable reply draft (never sent in dry-run)
let replyDraft;
if (intent === 'unsupported_intent') {
  replyDraft = answer + (hint ? '\nHint: ' + hint : '');
} else {
  replyDraft = answer;
  if (rowCount > 0 && Array.isArray(body.rows) && body.rows.length > 0) {
    // Append compact row summary (first 5)
    const rows = body.rows.slice(0, 5);
    const cols = Object.keys(rows[0]).filter(c => !['booking_id','payment_id'].includes(c));
    rows.forEach(function(r) {
      replyDraft += '\n' + cols.map(c => c + ': ' + (r[c] == null ? '' : String(r[c]))).join(' | ');
    });
    if (body.rows.length > 5) {
      replyDraft += '\n(+' + (body.rows.length - 5) + ' more)';
    }
  }
}

return [{
  json: {
    // Safety flags — always false in dry-run
    whatsapp_sent:        false,
    dry_run:              true,
    live_send_blocked:    true,
    // Source context
    staff_phone:          parsed.staff_phone,
    question:             parsed.question,
    client_slug:          parsed.client_slug,
    source:               'staff_whatsapp',
    // API result
    intent:               intent,
    answer:               answer,
    row_count:            rowCount,
    // Draft (never sent)
    reply_draft:          replyDraft,
    // Pass-through for audit
    read_only:            body.read_only   !== false,
    no_write_performed:   body.no_write_performed !== false,
    _stage:               '8.6.3'
  }
}];
